#include<bits/stdc++.h>
using namespace std;
set<int> s[200010];
int main()
{
    int n,m;
    scanf("%d%d",&n,&m);
    for(int i=1;i<=m;i++)
    {
        int u,v;
        scanf("%d%d",&u,&v);
        s[min(u,v)].insert(max(u,v));
    }
    long long ans=-m;
    for(int i=1;i<=n;i++)
    {
        if(s[i].empty())
        {
            continue;
        }
        ans+=s[i].size();
        int u=(*s[i].begin()),v=i;
        s[v].erase(s[v].begin());
        if(s[u].size()<s[v].size())
        {
            swap(s[u],s[v]);
        }
        for(int i:s[v])
        {
            s[u].insert(i);
        }
    }
    printf("%lld",ans);
    return 0;
}
